export function getThisWeekOrigin(): Date {
  const today: Date = new Date();
  const dayOfToday: number = today.getDay();
  const originDate: number = today.getDate() - dayOfToday;
  const origin: Date = new Date();
  origin.setDate(originDate);
  origin.setHours(0);
  origin.setMinutes(0);
  origin.setSeconds(0);
  origin.setMilliseconds(0);
  return origin;
}

export function offsetDate(origin: Date, date: number, hours: number, minutes: number): Date {
  const duplicatedOrigin = new Date();
  duplicatedOrigin.setDate(1);
  duplicatedOrigin.setMonth(0);
  duplicatedOrigin.setHours(hours);
  duplicatedOrigin.setMinutes(minutes);
  duplicatedOrigin.setSeconds(0);
  duplicatedOrigin.setMilliseconds(0);
  duplicatedOrigin.setFullYear(origin.getFullYear());
  duplicatedOrigin.setMonth(origin.getMonth());
  duplicatedOrigin.setDate(origin.getDate());
  duplicatedOrigin.setDate(duplicatedOrigin.getDate() + date);
  return duplicatedOrigin;
}

/**
 * parse the timestamp of a specific dataset as JavaScript-native timestamp
 * @param x a timestamp with years, months, date, hours, minutes and seconds placed in order
 * @param timeZoneOffset offset = UTC - time (measured in minutes); UTC±T -> offset = ∓60 * T
 * @returns the value of Date.getTime()
 */
export function timestampToNumber(x: string, timeZoneOffset: number = 0): number {
  const regex = /[0-9\.]*/gm;
  const match = x.match(regex);
  if (match) {
    const localTimeZoneOffset = new Date().getTimezoneOffset();
    const year = parseInt(match[0], 10);
    const month = parseInt(match[2], 10);
    const date = parseInt(match[4], 10);
    const hours = parseInt(match[6], 10);
    const minutes = parseInt(match[8], 10);
    const seconds = parseInt(match[10], 10);
    const date_object = new Date();
    date_object.setDate(1);
    date_object.setMonth(0);
    date_object.setFullYear(year);
    date_object.setMonth(month - 1);
    date_object.setDate(date);
    date_object.setHours(hours);
    date_object.setMinutes(minutes + timeZoneOffset - localTimeZoneOffset);
    // UTC - source = source offset -> UTC = source + soucre offset
    // UTC - local = local offset -> local = UTC - local offset = (source + soucre offset) - local offset
    date_object.setSeconds(seconds);
    return date_object.getTime();
  }
  return 0;
}

export function dateToString(date: Date, template: string = 'YYYY-MM-DD hh:mm:ss'): string {
  const result = template
    .replaceAll(/Y{4,4}/g, date.getFullYear().toString())
    .replaceAll(/M{2,2}/g, (date.getMonth() + 1).toString().padStart(2, '0'))
    .replaceAll(/D{2,2}/g, date.getDate().toString().padStart(2, '0'))
    .replaceAll(/h{2,2}/g, date.getHours().toString().padStart(2, '0'))
    .replaceAll(/m{2,2}/g, date.getMinutes().toString().padStart(2, '0'))
    .replaceAll(/s{2,2}/g, date.getSeconds().toString().padStart(2, '0'))
    .replaceAll(/W{2,2}/g, `週${['日', '一', '二', '三', '四', '五', '六'][date.getDay()]}`);
  return result;
}

export function dateToRelativeTime(date: Date): string {
  const time = date.getTime();
  const seconds = Math.floor((new Date().getTime() - time) / 1000);
  let interval = Math.floor(seconds / 31536000); // seconds in a year
  if (interval >= 1) {
    return `${interval}年前`;
  }
  interval = Math.floor(seconds / 2592000); // seconds in a month
  if (interval >= 1) {
    return `${interval}個月前`;
  }
  interval = Math.floor(seconds / 86400); // seconds in a day
  if (interval >= 1) {
    return `${interval}天前`;
  }
  interval = Math.floor(seconds / 3600); // seconds in an hour
  if (interval >= 1) {
    return `${interval}小時前`;
  }
  interval = Math.floor(seconds / 60); // seconds in a minute
  if (interval >= 1) {
    return `${interval}分鐘前`;
  }
  if (seconds > 0) {
    return `${seconds}秒前`;
  }
  return '現在';
}

export function formatTime(time: number, mode: number): string {
  const roundedTime = time | 0;
  switch (mode) {
    case 0: {
      return `${roundedTime}秒`;
    }
    case 1: {
      const minutes = (roundedTime - (roundedTime % 60)) / 60;
      const seconds = roundedTime % 60;
      return `${minutes < 10 ? '0' : ''}${minutes.toString()}:${seconds < 10 ? '0' : ''}${seconds.toString()}`;
    }
    case 2: {
      const minutes = (roundedTime / 60) | 0;
      return `${minutes}分`;
    }
    case 3: {
      if (60 * 60 <= roundedTime) {
        const hours = (((roundedTime / (60 * 60)) * 10) | 0) / 10;
        return `${hours}時`;
      } else if (60 <= roundedTime) {
        const minutes = (roundedTime / 60) | 0;
        return `${minutes}分`;
      } else {
        return `${roundedTime}秒`;
      }
    }
    default: {
      return '--';
    }
  }
}

/**
 * - 0: Sunday
 * - 1: Monday
 * - 2: Tuesday
 * - 3: Wednesday
 * - 4: Thursday
 * - 5: Friday
 * - 6: Saturday
 */
export type WeekDayIndex = 0 | 1 | 2 | 3 | 4 | 5 | 6;

export type WeekDayIndexArray = Array<WeekDayIndex>;

export type WeekDayName = '日' | '一' | '二' | '三' | '四' | '五' | '六';

export interface WeekDay {
  name: WeekDayName;
  day: WeekDayIndex;
  code: string;
}

export type WeeklyArray<T> = [sun: T, mon: T, tue: T, wed: T, thu: T, fri: T, sat: T];

export function indexToDay(index: WeekDayIndex): WeekDay {
  const days: Array<WeekDay> = [
    {
      name: '日',
      day: 0,
      code: 'd_0'
    },
    {
      name: '一',
      day: 1,
      code: 'd_1'
    },
    {
      name: '二',
      day: 2,
      code: 'd_2'
    },
    {
      name: '三',
      day: 3,
      code: 'd_3'
    },
    {
      name: '四',
      day: 4,
      code: 'd_4'
    },
    {
      name: '五',
      day: 5,
      code: 'd_5'
    },
    {
      name: '六',
      day: 6,
      code: 'd_6'
    }
  ];
  return days[index];
}

export function dateValueToDayOfWeek(dateValue: string): WeekDay {
  const int = parseInt(dateValue, 10);
  const index = (int - 1) as WeekDayIndex;
  return indexToDay(index);
}

export interface TimeObject {
  hours: number;
  minutes: number;
}

export interface TimePeriod {
  start: TimeObject;
  end: TimeObject;
}

export interface TimeStampPeriod {
  start: Date;
  end: Date;
}

export function timeObjectToString(timeObject: TimeObject): string {
  // timeObject.hours >= 0 and timeObject.minutes >= 0
  return `${timeObject.hours < 10 ? '0' : ''}${timeObject.hours.toString()}:${timeObject.minutes < 10 ? '0' : ''}${timeObject.minutes.toString()}`;
}

export function createDateObjectFromDate(year: number, month: number, date: number): Date {
  const dateObject = new Date();
  dateObject.setDate(1); // Set to the first day of the month to prevent date from being clamped
  dateObject.setMonth(0);
  dateObject.setFullYear(year);
  dateObject.setMonth(month - 1);
  dateObject.setDate(date);
  dateObject.setHours(0);
  dateObject.setMinutes(0);
  dateObject.setSeconds(0);
  dateObject.setMilliseconds(0);
  return dateObject;
}
